// Stack vertical no mobile, horizontal no desktop
<div className="flex flex-col lg:flex-row gap-4">
  <Sidebar />   {/* Em cima no mobile, esquerda no desktop */}
  <Content />   {/* Embaixo no mobile, direita no desktop */}
